const {
  SCRIPT_EXTENSIONS_REGEX,
  FILE_TO_ROUTE_REGEX,
  FOLDER_WITH_PARAMS_REGEX,
  FILE_WITH_PARAMS_REGEX,
  FOLDER_WITH_CATCH_ALL_REGEX,
  FILE_WITH_CATCH_ALL_REGEX,
  INDEX_FILE_TO_ROUTE_REGEX,
  NORDIC_PAGE_ABSOLUTE_PATH_TO_RELATIVE_REGEX,
  STARTS_WITH_INDEX_REGEX,
  BASENAME_REGEX,
} = require('../constants/regexs');
const {
  ISLANDS_DIR,
  NORDIC_PAGES_DIR,
} = require('../constants/files-discovery');
const { getPathSegments } = require('./file/path-detail');

const normalizeIslandClientName = (client) => {
  const clientName = client.toLowerCase();

  const pagesDirPath = /^.*app\//;

  return `nordic-island${clientName
    .replace(pagesDirPath, '/')
    .replace(ISLANDS_DIR, '/')
    .replace(NORDIC_PAGES_DIR, '')
    .replace(SCRIPT_EXTENSIONS_REGEX, '')
    .replace('//', '/')
    .replace(/\//g, '-')
    .replace(/\[(.*)\]/g, '$1')
    .toLowerCase()}`;
};

/**
 * Normalize the page Express route
 * When normalizing:
 * - Open bracket is replaced by colon ( '[' => ':' )
 * - Close bracket is removed ( ']' )
 * - 'index' and 'styles' begin occurrences are removed
 * - '.hooks.server' and file extensions occurrences (Example: .js, .scss, .ts) are removed
 * - Device type occurrences (Example: .desktop, .mobile) are removed
 * - '/styles' and '/index' file names are replaced by slash ( ('/styles' | '/index') => '/' )
 * @param { string } navigablePageFile - Non-normalized page file path
 * @returns { string } Normalized page Express route
 *
 * @example
 * normalizePathToExpressRoute('item/[id]/index.js') returns 'item/:id'
 * normalizePathToExpressRoute('item/[...param]/index.js') returns 'item/*'
 * normalizePathToExpressRoute('item/[...param]') returns 'item/*'
 */
const normalizePathToExpressRoute = (navigablePageFile) => {
  const segments = getPathSegments(navigablePageFile);

  let pageRoute = segments
    .map((pagePath, index) => {
      const isLastSegment = index === segments.length - 1;
      const paramsRegexExec = (
        isLastSegment ? FILE_WITH_PARAMS_REGEX : FOLDER_WITH_PARAMS_REGEX
      ).exec(pagePath);
      const catchAllRegexExec = (
        isLastSegment ? FILE_WITH_CATCH_ALL_REGEX : FOLDER_WITH_CATCH_ALL_REGEX
      ).exec(pagePath);

      if (!paramsRegexExec && !catchAllRegexExec) {
        return pagePath;
      }

      const [, pathName, pathExt = ''] = paramsRegexExec || catchAllRegexExec;

      return `${catchAllRegexExec ? '*' : `:${pathName}`}${pathExt}`;
    })
    .join('/');

  pageRoute = `/${pageRoute.replace(FILE_TO_ROUTE_REGEX, '')}`;

  return pageRoute.replace(INDEX_FILE_TO_ROUTE_REGEX, '').replace(/\/\//g, '/');
};

/**
 * Normalize the http error status code
 * When normalizing:
 * - File extensions occurrences (Example: .js, .scss, .ts) are removed
 * - Device type occurrences (Example: .desktop, .mobile) are removed
 * - '/styles' and '/index' file names are removed
 * @param { string } httpErrorPageFile - Non-normalized http error file path
 * @returns { string } Normalized http error status code
 *
 * @example
 * normalizePathToPageErrorStatusCode('404/index.mobile.scss') returns '404'
 */
const normalizePathToPageErrorStatusCode = (httpErrorPageFile) =>
  httpErrorPageFile
    .replace(FILE_TO_ROUTE_REGEX, '')
    .replace(INDEX_FILE_TO_ROUTE_REGEX, '');

/**
 * Normalize the page data id
 * When normalizing:
 * - File extensions occurrences (Example: .js, .scss, .ts) are removed
 * - Device type occurrences (Example: .desktop, .mobile) are removed
 * - '/styles' and '/index' file names are removed
 * @param { string } navigablePageFile - Non-normalized navigable file path
 * @returns { string } Normalized page data id
 *
 * @example
 * normalizePathToPageDataId('my-app/app/nordic-pages/home/help/index.desktop.js') returns 'home/help'
 * normalizePathToPageDataId('my-app/app/nordic-pages/index.desktop.js') returns '/'
 * normalizePathToPageDataId('my-app/app/nordic-pages/product/[id].js') returns '[id]'
 */
const normalizePathToPageDataId = (navigablePageFile) =>
  navigablePageFile
    .replace(NORDIC_PAGE_ABSOLUTE_PATH_TO_RELATIVE_REGEX, '/')
    .replace(BASENAME_REGEX, '')
    .replace(STARTS_WITH_INDEX_REGEX, '/')
    .replace(INDEX_FILE_TO_ROUTE_REGEX, '');

module.exports = {
  normalizeIslandClientName,
  normalizePathToExpressRoute,
  normalizePathToPageErrorStatusCode,
  normalizePathToPageDataId,
};
